const body = $('Webhook').first().json.body || {};
const match_pair_id = String(body.match_pair_id || '').trim();
const session_id = String(body.session_id || '').trim();
const image_urls = Array.isArray(body.image_urls) ? body.image_urls.filter(u => typeof u === 'string' && u.startsWith('http')) : [];
if (!match_pair_id || !session_id) throw new Error('match_pair_id and session_id required');

const all = $input.all().map(i => i.json);
const userRows = all.filter(r => 'session_id' in r && !('Match Pair Id' in r));
const msgRows  = all.filter(r => 'Match Pair Id' in r);

const pairSids = match_pair_id.split('__');
const bySid = new Map();
for (const u of userRows) {
  const sid = String(u.session_id || '').trim();
  if (sid) bySid.set(sid, u);
}
const meRow = bySid.get(session_id);
const youSid = pairSids.find(s => s !== session_id);
const youRow = bySid.get(youSid);
if (!meRow || !youRow) throw new Error('match pair not found in user_vectors');

const pairMsgs = msgRows
  .filter(r => String(r['Match Pair Id']) === match_pair_id && String(r['From Session Id']) !== 'system' && !String(r['Text'] || '').startsWith('__'))
  .map(r => ({
    from: (String(r['From Session Id']) === session_id) ? 'me' : 'them',
    text: String(r['Text'] || '').trim(),
    ts: r['Timestamp'] ? Date.parse(r['Timestamp']) : 0
  }))
  .filter(m => m.text.length > 0)
  .sort((a,b) => a.ts - b.ts);

// Conversation transcript for the LLM. Cap to keep prompt small.
const transcript = pairMsgs.slice(-30).map(m => `${m.from}: ${m.text}`).join('\n');
const message_count = pairMsgs.length;
const duration_minutes = (pairMsgs.length >= 2) ? Math.round((pairMsgs[pairMsgs.length-1].ts - pairMsgs[0].ts) / 60000) : 0;

// Quadrant label from me final_P/A
const P = Number(meRow.final_P), A = Number(meRow.final_A);
const quadrant = (P>=0 && A>=0) ? 'joy' : (P>=0 && A<0) ? 'calm' : (P<0 && A>=0) ? 'anxious' : 'melancholy';

// Background image: random from the 3 user-provided images. Fallback to a bucket image derived from initial_P/A.
function bucketId(iP, iA) {
  const p = Number(iP), a = Number(iA);
  const col = a >= 0.35 ? 0 : a >= -0.35 ? 1 : 2;
  const row = p >= 0.35 ? 0 : p >= -0.35 ? 1 : 2;
  return row*3 + col + 1;
}
const buck = bucketId(meRow.initial_P, meRow.initial_A);
let background_image_url;
if (image_urls.length > 0) {
  // pick a stable one per pair
  let hash = 5381;
  for (let i=0;i<match_pair_id.length;i++) hash=((hash<<5)+hash)+match_pair_id.charCodeAt(i);
  background_image_url = image_urls[(hash >>> 0) % image_urls.length];
} else {
  background_image_url = '';
}

return [{ json: {
  match_pair_id,
  session_id,
  me_city: String(meRow.city || ''),
  me_lat: Number(meRow.lat) || null,
  me_lng: Number(meRow.lng) || null,
  partner_city: String(youRow.city || ''),
  partner_lat: Number(youRow.lat) || null,
  partner_lng: Number(youRow.lng) || null,
  mode: String(meRow.match_mode || 'echo'),
  quadrant,
  bucket: buck,
  message_count,
  duration_minutes,
  transcript,
  background_image_url,
  _no_chat: transcript.length === 0
} }];

parameters.text:
=Two strangers just ended an anonymous ~15-minute chat on an emotion-matching app called Resonance.
Mode: {{ $json.mode }}  (echo = they shared the same emotional weather; healing = complementary, one talked and one listened)
Shared emotional quadrant: {{ $json.quadrant }}
Cities: {{ $json.me_city }}  ↔  {{ $json.partner_city }}
Messages exchanged: {{ $json.message_count }}
Duration: {{ $json.duration_minutes }} minutes

Transcript (me = the requester, them = the stranger):
{{ $json.transcript }}

Task: write ONE warm, specific, non-generic sentence (under 18 words) that captures the feeling of this exchange. It will be printed on a postcard they can keep. No emojis. No quotes. Lowercase. Don't name emotions directly. Don't mention the app. Don't use the word "journey" or "beautiful". Respond with only the sentence.

