const ctx = $('Prepare Context').first().json;
const raw = $input.first().json;
let highlight = String(raw.output || raw.text || '').trim();
highlight = highlight.replace(/^["'“”]|["'“”]$/g,'').trim();
if (!highlight) highlight = 'a small window opened for a little while, and then closed.';

// Subtitle: city-to-city + duration
const cityLine = (ctx.me_city && ctx.partner_city) ? `${ctx.me_city} ↔ ${ctx.partner_city}` : '';
const durLine = ctx.duration_minutes > 0 ? `${ctx.duration_minutes} min, ${ctx.message_count} messages` : `${ctx.message_count} messages`;

return [{ json: {
  ok: true,
  match_pair_id: ctx.match_pair_id,
  highlight,
  subtitle: [cityLine, durLine].filter(Boolean).join(' · '),
  me_city: ctx.me_city,
  me_lat: ctx.me_lat,
  me_lng: ctx.me_lng,
  partner_city: ctx.partner_city,
  partner_lat: ctx.partner_lat,
  partner_lng: ctx.partner_lng,
  mode: ctx.mode,
  quadrant: ctx.quadrant,
  bucket: ctx.bucket,
  message_count: ctx.message_count,
  duration_minutes: ctx.duration_minutes,
  background_image_url: ctx.background_image_url
} }];

// Fallback when no chat messages exist.
const ctx = $('Prepare Context').first().json;
const highlight = ctx.mode === 'healing' ? 'you showed up for each other, even without words.' : 'the same quiet moment, shared across the distance.';
const cityLine = (ctx.me_city && ctx.partner_city) ? `${ctx.me_city} ↔ ${ctx.partner_city}` : '';
return [{ json: {
  ok: true,
  match_pair_id: ctx.match_pair_id,
  highlight,
  subtitle: cityLine,
  me_city: ctx.me_city,
  me_lat: ctx.me_lat,
  me_lng: ctx.me_lng,
  partner_city: ctx.partner_city,
  partner_lat: ctx.partner_lat,
  partner_lng: ctx.partner_lng,
  mode: ctx.mode,
  quadrant: ctx.quadrant,
  bucket: ctx.bucket,
  message_count: 0,
  duration_minutes: 0,
  background_image_url: ctx.background_image_url
} }];
